import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.BtKjyiyt.js";const g=JSON.parse('{"title":"Notebook Basics","description":"","frontmatter":{},"headers":[],"relativePath":"notebook-basics.md","filePath":"notebook-basics.md","lastUpdated":null}'),l={name:"notebook-basics.md"};function i(n,e,d,r,c,h){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="Notebook-Basics" tabindex="-1">Notebook Basics <a class="header-anchor" href="#Notebook-Basics" aria-label="Permalink to &quot;Notebook Basics {#Notebook-Basics}&quot;">​</a></h1><h2 id="Cell-types" tabindex="-1">Cell types <a class="header-anchor" href="#Cell-types" aria-label="Permalink to &quot;Cell types {#Cell-types}&quot;">​</a></h2><ul><li><p><strong>Code cells</strong> evaluate Julia. The last expression&#39;s value renders below, along with stdout and any rich display (images, ECharts, tables, LaTeX).</p></li><li><p><strong>Markdown cells</strong> render GitHub-flavored markdown with LaTeX math and double-brace interpolation of Julia values.</p></li></ul><p>Toggle a cell&#39;s type with the header button (<code>M↓</code> / <code>{·}</code>) or press <code>m</code> / <code>y</code> in command mode.</p><p>A code cell shows an always-on editor with tree-based Julia highlighting (CodeMirror 6 + the Lezer Julia grammar), the run button, timing, and state badge:</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/editor-highlighting.png" alt=""></p><h2 id="Command-mode-vs.-edit-mode" tabindex="-1">Command mode vs. edit mode <a class="header-anchor" href="#Command-mode-vs.-edit-mode" aria-label="Permalink to &quot;Command mode vs. edit mode {#Command-mode-vs.-edit-mode}&quot;">​</a></h2><p>KaimonSlate uses a Jupyter-style two-mode model:</p><ul><li><p><strong>Command mode</strong> — the cell has an accent ring and single keys act on it.</p></li><li><p><strong>Edit mode</strong> — focus is inside the editor (green ring); <code>Esc</code> returns to command mode.</p></li></ul><table tabindex="0"><thead><tr><th style="text-align:right;">Key</th><th style="text-align:right;">Action</th></tr></thead><tbody><tr><td style="text-align:right;"><code>↑</code>/<code>k</code>, <code>↓</code>/<code>j</code></td><td style="text-align:right;">move selection</td></tr><tr><td style="text-align:right;"><code>⇧↑</code> / <code>⇧↓</code></td><td style="text-align:right;"><strong>move the cell</strong> up/down</td></tr><tr><td style="text-align:right;"><code>⏎</code></td><td style="text-align:right;">enter edit mode</td></tr><tr><td style="text-align:right;"><code>a</code> / <code>b</code></td><td style="text-align:right;">add cell above / below</td></tr><tr><td style="text-align:right;"><code>m</code> / <code>y</code></td><td style="text-align:right;">to markdown / to code</td></tr><tr><td style="text-align:right;"><code>dd</code></td><td style="text-align:right;">delete cell</td></tr><tr><td style="text-align:right;"><code>⇧M</code></td><td style="text-align:right;">merge with the cell below</td></tr></tbody></table><p>In edit mode:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Key</th><th style="text-align:right;">Action</th></tr></thead><tbody><tr><td style="text-align:right;"><code>⇧⏎</code></td><td style="text-align:right;">run (or commit a markdown/bind cell)</td></tr><tr><td style="text-align:right;"><code>⌘⇧⏎</code> / <code>Ctrl⇧⏎</code></td><td style="text-align:right;">run and open a fresh cell below</td></tr><tr><td style="text-align:right;"><code>⌘⇧-</code> / <code>Ctrl⇧-</code></td><td style="text-align:right;">split the cell at the cursor</td></tr><tr><td style="text-align:right;"><code>⇥</code></td><td style="text-align:right;">completion (Julia REPL completions + cell-local bindings)</td></tr></tbody></table><p>Notebook-wide: <strong>⌘Z / ⌘⇧Z</strong> undo/redo structural changes, <strong>⌘K</strong> the command palette, <strong>⌘⇧K</strong> the docs search palette.</p><h2 id="Running-cells" tabindex="-1">Running cells <a class="header-anchor" href="#Running-cells" aria-label="Permalink to &quot;Running cells {#Running-cells}&quot;">​</a></h2><p>Run a single cell with <strong>⇧⏎</strong>, or <strong>▶ Run stale</strong> in the top bar to recompute every stale cell. The kernel dot in the top bar breathes while a computation is in flight.</p><h2 id="Quiet-cells" tabindex="-1">Quiet cells <a class="header-anchor" href="#Quiet-cells" aria-label="Permalink to &quot;Quiet cells {#Quiet-cells}&quot;">​</a></h2><p>A code cell whose last non-comment line ends in <code>;</code> suppresses display of the value (stdout and explicit <code>display()</code> still show) — handy for setup cells.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">big </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> rand</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># no 1000×1000 dump</span></span></code></pre></div><h2 id="Markdown-interpolation" tabindex="-1">Markdown interpolation <a class="header-anchor" href="#Markdown-interpolation" aria-label="Permalink to &quot;Markdown interpolation {#Markdown-interpolation}&quot;">​</a></h2><p>Inside a markdown cell, a double-brace <code>expr</code> block splices a Julia value into the rendered output:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Mean: {{ round(mean(data); digits=2) }}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ echart(spec) }}          &lt;!-- an interactive chart --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ slate_table(df) }}       &lt;!-- an interactive table --&gt;</span></span></code></pre></div><p>Scalars render inline; images, charts, and tables render as blocks. Interpolation works inside math (<code>$…$</code>) too.</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/markdown.png" alt=""></p><h2 id="completion" tabindex="-1">Completion <a class="header-anchor" href="#completion" aria-label="Permalink to &quot;Completion&quot;">​</a></h2><p>Tab-completion uses Julia&#39;s REPL completions against the live kernel <strong>plus</strong> the cell&#39;s own local bindings (assignments, loop/comprehension variables, function parameters) so names complete even before the cell has run. The popup carries a docstring preview, and method completions insert tab-through argument placeholders. LaTeX/emoji shortcuts work — type <code>\\pi</code>⇥ → <code>π</code>.</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/completion.png" alt=""></p><h2 id="Renaming-cells" tabindex="-1">Renaming cells <a class="header-anchor" href="#Renaming-cells" aria-label="Permalink to &quot;Renaming cells {#Renaming-cells}&quot;">​</a></h2><p>Cell ids are header-safe labels. Double-click a cell&#39;s id to rename it; renames are tracked as renames in <a href="./history">history</a>, and dependencies (which are by id) are rebuilt.</p>`,28)])])}const m=t(l,[["render",i]]);export{g as __pageData,m as default};
